begin;
create table if not exists public.lead_contact_preferences(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,lead_id uuid not null references public.leads(id) on delete cascade,channel text not null check(channel in('whatsapp','email','phone','sms')),consent_status text not null default 'unknown' check(consent_status in('unknown','granted','denied')),lawful_basis text,evidence text,preferred boolean not null default false,allowed_start time not null default '09:00',allowed_end time not null default '20:00',allowed_days smallint[] not null default '{1,2,3,4,5,6}'check(allowed_days<@array[1,2,3,4,5,6,7]::smallint[]),timezone text not null default 'America/Sao_Paulo',valid_until timestamptz,granted_at timestamptz,revoked_at timestamptz,updated_by uuid not null references public.profiles(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(organization_id,lead_id,channel),check(allowed_end>allowed_start));
create table if not exists public.lead_contact_preference_events(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,lead_id uuid not null references public.leads(id) on delete cascade,preference_id uuid not null references public.lead_contact_preferences(id) on delete cascade,actor_id uuid not null references public.profiles(id),previous_status text,new_status text not null,channel text not null,evidence text not null,created_at timestamptz not null default now());create index if not exists lead_contact_preferences_eligibility_idx on public.lead_contact_preferences(organization_id,lead_id,channel,consent_status,valid_until);alter table public.lead_contact_preferences enable row level security;alter table public.lead_contact_preference_events enable row level security;drop policy if exists lead_contact_preferences_scope on public.lead_contact_preferences;create policy lead_contact_preferences_scope on public.lead_contact_preferences for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_lead(lead_id)));drop policy if exists lead_contact_preference_events_scope on public.lead_contact_preference_events;create policy lead_contact_preference_events_scope on public.lead_contact_preference_events for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_lead(lead_id)));revoke all on public.lead_contact_preferences,public.lead_contact_preference_events from anon;revoke insert,update,delete on public.lead_contact_preferences,public.lead_contact_preference_events from authenticated;grant select on public.lead_contact_preferences,public.lead_contact_preference_events to authenticated;
create or replace function public.set_lead_contact_preference(p_actor_id uuid,p_organization_id uuid,p_lead_id uuid,p_channel text,p_status text,p_lawful_basis text,p_evidence text,p_preferred boolean,p_allowed_start time,p_allowed_end time,p_allowed_days smallint[],p_timezone text,p_valid_until timestamptz)returns jsonb language plpgsql security definer set search_path='' as $$declare actor_ok boolean;target public.lead_contact_preferences;previous text;recipient text;begin select exists(select 1 from public.profiles p where p.id=p_actor_id and p.organization_id=p_organization_id and p.active=true and(p.id=(select assigned_to from public.leads where id=p_lead_id and organization_id=p_organization_id)or coalesce(p.commercial_role,case p.role when'admin'then'director'else p.role end)in('director','superintendent','manager')))into actor_ok;if not actor_ok then raise exception 'contact_preference_actor_forbidden';end if;if p_channel not in('whatsapp','email','phone','sms')or p_status not in('unknown','granted','denied')or char_length(trim(coalesce(p_evidence,'')))<10 or p_allowed_end<=p_allowed_start or coalesce(array_length(p_allowed_days,1),0)<1 or p_timezone!~'^[A-Za-z_]+/[A-Za-z_]+$'or p_status='granted'and char_length(trim(coalesce(p_lawful_basis,'')))<5 then raise exception 'contact_preference_invalid';end if;select * into target from public.lead_contact_preferences where organization_id=p_organization_id and lead_id=p_lead_id and channel=p_channel for update;previous:=coalesce(target.consent_status,'unknown');insert into public.lead_contact_preferences(organization_id,lead_id,channel,consent_status,lawful_basis,evidence,preferred,allowed_start,allowed_end,allowed_days,timezone,valid_until,granted_at,revoked_at,updated_by)values(p_organization_id,p_lead_id,p_channel,p_status,nullif(trim(p_lawful_basis),''),trim(p_evidence),p_preferred,p_allowed_start,p_allowed_end,p_allowed_days,p_timezone,p_valid_until,case when p_status='granted'then now()end,case when p_status='denied'then now()end,p_actor_id)on conflict(organization_id,lead_id,channel)do update set consent_status=excluded.consent_status,lawful_basis=excluded.lawful_basis,evidence=excluded.evidence,preferred=excluded.preferred,allowed_start=excluded.allowed_start,allowed_end=excluded.allowed_end,allowed_days=excluded.allowed_days,timezone=excluded.timezone,valid_until=excluded.valid_until,granted_at=case when excluded.consent_status='granted'then now()else lead_contact_preferences.granted_at end,revoked_at=case when excluded.consent_status='denied'then now()else null end,updated_by=p_actor_id,updated_at=now()returning * into target;insert into public.lead_contact_preference_events(organization_id,lead_id,preference_id,actor_id,previous_status,new_status,channel,evidence)values(p_organization_id,p_lead_id,target.id,p_actor_id,previous,p_status,p_channel,trim(p_evidence));select case when p_channel in('whatsapp','sms','phone')then phone_normalized else email_normalized end into recipient from public.leads where id=p_lead_id and organization_id=p_organization_id;if recipient is not null and p_status='denied'then insert into public.messaging_suppressions(organization_id,channel,recipient,reason,source)values(p_organization_id,p_channel,recipient,'opt_out','lead_contact_preference')on conflict(organization_id,channel,recipient)do update set reason='opt_out',source='lead_contact_preference';elsif recipient is not null and p_status='granted'then delete from public.messaging_suppressions where organization_id=p_organization_id and channel=p_channel and recipient=recipient and source='lead_contact_preference';end if;return jsonb_build_object('leadId',p_lead_id,'channel',p_channel,'consentStatus',p_status,'preferred',p_preferred,'auditable',true,'automationRecheckRequired',true);end $$;
create or replace function public.check_lead_contact_eligibility(p_organization_id uuid,p_lead_id uuid,p_channel text,p_at timestamptz default now())returns jsonb language plpgsql security definer set search_path='' stable as $$declare pref public.lead_contact_preferences;local_time timestamp;recipient text;suppressed boolean;begin select * into pref from public.lead_contact_preferences where organization_id=p_organization_id and lead_id=p_lead_id and channel=p_channel;if pref.id is null then return jsonb_build_object('eligible',false,'reason','consent_not_recorded','channel',p_channel);end if;select case when p_channel in('whatsapp','sms','phone')then phone_normalized else email_normalized end into recipient from public.leads where id=p_lead_id and organization_id=p_organization_id and duplicate_state<>'merged';if recipient is null then return jsonb_build_object('eligible',false,'reason','recipient_unavailable','channel',p_channel);end if;select exists(select 1 from public.messaging_suppressions where organization_id=p_organization_id and channel=p_channel and recipient=recipient)into suppressed;if suppressed or pref.consent_status='denied'then return jsonb_build_object('eligible',false,'reason','opt_out','channel',p_channel);end if;if pref.consent_status<>'granted'then return jsonb_build_object('eligible',false,'reason','consent_not_granted','channel',p_channel);end if;if pref.valid_until is not null and pref.valid_until<p_at then return jsonb_build_object('eligible',false,'reason','consent_expired','channel',p_channel);end if;local_time:=p_at at time zone pref.timezone;if not extract(isodow from local_time)::smallint=any(pref.allowed_days)or local_time::time<pref.allowed_start or local_time::time>=pref.allowed_end then return jsonb_build_object('eligible',false,'reason','outside_contact_window','channel',p_channel,'nextManualReview',true);end if;return jsonb_build_object('eligible',true,'reason','consent_and_window_valid','channel',p_channel,'preferred',pref.preferred,'validUntil',pref.valid_until,'checkedAt',p_at);exception when invalid_parameter_value then return jsonb_build_object('eligible',false,'reason','invalid_timezone','channel',p_channel);end $$;
-- Redefinições qualificadas evitam qualquer ambiguidade entre variáveis e colunas.
create or replace function public.set_lead_contact_preference(p_actor_id uuid,p_organization_id uuid,p_lead_id uuid,p_channel text,p_status text,p_lawful_basis text,p_evidence text,p_preferred boolean,p_allowed_start time,p_allowed_end time,p_allowed_days smallint[],p_timezone text,p_valid_until timestamptz)returns jsonb language plpgsql security definer set search_path='' as $$
declare actor_ok boolean;target public.lead_contact_preferences;previous text;contact_value text;
begin
 select exists(select 1 from public.profiles p where p.id=p_actor_id and p.organization_id=p_organization_id and p.active=true and(p.id=(select l.assigned_to from public.leads l where l.id=p_lead_id and l.organization_id=p_organization_id)or coalesce(p.commercial_role,case p.role when'admin'then'director'else p.role end)in('director','superintendent','manager')))into actor_ok;
 if not actor_ok then raise exception 'contact_preference_actor_forbidden';end if;
 if p_channel not in('whatsapp','email','phone','sms')or p_status not in('unknown','granted','denied')or char_length(trim(coalesce(p_evidence,'')))<10 or p_allowed_end<=p_allowed_start or coalesce(array_length(p_allowed_days,1),0)<1 or p_timezone!~'^[A-Za-z_]+/[A-Za-z_]+$'or(p_status='granted'and char_length(trim(coalesce(p_lawful_basis,'')))<5)then raise exception 'contact_preference_invalid';end if;
 select * into target from public.lead_contact_preferences cp where cp.organization_id=p_organization_id and cp.lead_id=p_lead_id and cp.channel=p_channel for update;previous:=coalesce(target.consent_status,'unknown');
 insert into public.lead_contact_preferences(organization_id,lead_id,channel,consent_status,lawful_basis,evidence,preferred,allowed_start,allowed_end,allowed_days,timezone,valid_until,granted_at,revoked_at,updated_by)values(p_organization_id,p_lead_id,p_channel,p_status,nullif(trim(p_lawful_basis),''),trim(p_evidence),p_preferred,p_allowed_start,p_allowed_end,p_allowed_days,p_timezone,p_valid_until,case when p_status='granted'then now()end,case when p_status='denied'then now()end,p_actor_id)on conflict(organization_id,lead_id,channel)do update set consent_status=excluded.consent_status,lawful_basis=excluded.lawful_basis,evidence=excluded.evidence,preferred=excluded.preferred,allowed_start=excluded.allowed_start,allowed_end=excluded.allowed_end,allowed_days=excluded.allowed_days,timezone=excluded.timezone,valid_until=excluded.valid_until,granted_at=case when excluded.consent_status='granted'then now()else lead_contact_preferences.granted_at end,revoked_at=case when excluded.consent_status='denied'then now()else null end,updated_by=p_actor_id,updated_at=now()returning * into target;
 insert into public.lead_contact_preference_events(organization_id,lead_id,preference_id,actor_id,previous_status,new_status,channel,evidence)values(p_organization_id,p_lead_id,target.id,p_actor_id,previous,p_status,p_channel,trim(p_evidence));
 select case when p_channel in('whatsapp','sms','phone')then l.phone_normalized else l.email_normalized end into contact_value from public.leads l where l.id=p_lead_id and l.organization_id=p_organization_id;
 if contact_value is not null and p_status='denied'then insert into public.messaging_suppressions(organization_id,channel,recipient,reason,source)values(p_organization_id,p_channel,contact_value,'opt_out','lead_contact_preference')on conflict(organization_id,channel,recipient)do update set reason='opt_out',source='lead_contact_preference';elsif contact_value is not null and p_status='granted'then delete from public.messaging_suppressions ms where ms.organization_id=p_organization_id and ms.channel=p_channel and ms.recipient=contact_value and ms.source='lead_contact_preference';end if;
 return jsonb_build_object('leadId',p_lead_id,'channel',p_channel,'consentStatus',p_status,'preferred',p_preferred,'auditable',true,'automationRecheckRequired',true);
end $$;
create or replace function public.check_lead_contact_eligibility(p_organization_id uuid,p_lead_id uuid,p_channel text,p_at timestamptz default now())returns jsonb language plpgsql security definer set search_path='' stable as $$
declare pref public.lead_contact_preferences;local_time timestamp;contact_value text;suppressed boolean;
begin select * into pref from public.lead_contact_preferences cp where cp.organization_id=p_organization_id and cp.lead_id=p_lead_id and cp.channel=p_channel;if pref.id is null then return jsonb_build_object('eligible',false,'reason','consent_not_recorded','channel',p_channel);end if;select case when p_channel in('whatsapp','sms','phone')then l.phone_normalized else l.email_normalized end into contact_value from public.leads l where l.id=p_lead_id and l.organization_id=p_organization_id and l.duplicate_state<>'merged';if contact_value is null then return jsonb_build_object('eligible',false,'reason','recipient_unavailable','channel',p_channel);end if;select exists(select 1 from public.messaging_suppressions ms where ms.organization_id=p_organization_id and ms.channel=p_channel and ms.recipient=contact_value)into suppressed;if suppressed or pref.consent_status='denied'then return jsonb_build_object('eligible',false,'reason','opt_out','channel',p_channel);end if;if pref.consent_status<>'granted'then return jsonb_build_object('eligible',false,'reason','consent_not_granted','channel',p_channel);end if;if pref.valid_until is not null and pref.valid_until<p_at then return jsonb_build_object('eligible',false,'reason','consent_expired','channel',p_channel);end if;local_time:=p_at at time zone pref.timezone;if not(extract(isodow from local_time)::smallint=any(pref.allowed_days))or local_time::time<pref.allowed_start or local_time::time>=pref.allowed_end then return jsonb_build_object('eligible',false,'reason','outside_contact_window','channel',p_channel,'nextManualReview',true);end if;return jsonb_build_object('eligible',true,'reason','consent_and_window_valid','channel',p_channel,'preferred',pref.preferred,'validUntil',pref.valid_until,'checkedAt',p_at);exception when invalid_parameter_value then return jsonb_build_object('eligible',false,'reason','invalid_timezone','channel',p_channel);end $$;
revoke all on function public.set_lead_contact_preference(uuid,uuid,uuid,text,text,text,text,boolean,time,time,smallint[],text,timestamptz),public.check_lead_contact_eligibility(uuid,uuid,text,timestamptz)from public,anon,authenticated;grant execute on function public.set_lead_contact_preference(uuid,uuid,uuid,text,text,text,text,boolean,time,time,smallint[],text,timestamptz),public.check_lead_contact_eligibility(uuid,uuid,text,timestamptz)to service_role;
commit;
